<?php
namespace App\Filament\Resources;
use App\Filament\Resources\TestimonialResource\Pages;use App\Models\Testimonial;use Filament\Actions\BulkActionGroup;use Filament\Actions\DeleteBulkAction;use Filament\Actions\EditAction;use Filament\Forms\Components\FileUpload;use Filament\Forms\Components\Textarea;use Filament\Forms\Components\TextInput;use Filament\Forms\Components\Toggle;use Filament\Resources\Resource;use Filament\Schemas\Schema;use Filament\Tables\Columns\IconColumn;use Filament\Tables\Columns\TextColumn;use Filament\Tables\Table;
class TestimonialResource extends Resource{protected static ?string $model=Testimonial::class;protected static ?string $navigationLabel='შეფასებები';public static function form(Schema $schema):Schema{return $schema->components([Textarea::make('quote')->label('შეფასება')->required()->rows(5),TextInput::make('author')->label('ავტორი')->required(),TextInput::make('role')->label('თანამდებობა'),TextInput::make('company')->label('კომპანია'),FileUpload::make('image')->image()->disk('public')->directory('testimonials'),Toggle::make('is_active')->default(true),TextInput::make('sort_order')->numeric()->default(0)]);}public static function table(Table $table):Table{return $table->columns([TextColumn::make('author')->searchable(),TextColumn::make('company'),TextColumn::make('quote')->limit(60),IconColumn::make('is_active')->boolean()])->defaultSort('sort_order')->recordActions([EditAction::make()])->toolbarActions([BulkActionGroup::make([DeleteBulkAction::make()])]);}public static function getPages():array{return ['index'=>Pages\ListTestimonials::route('/'),'create'=>Pages\CreateTestimonial::route('/create'),'edit'=>Pages\EditTestimonial::route('/{record}/edit')];}}
